const Q_CHEMISTRY_2005=[{"id": "objective>Chemistry>2005>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following equimolar solutions will have the highest pH?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COONa      </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaOH </div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl         </div>", "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>OH</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Among the given options, NaOH (Sodium Hydroxide) will have the highest pH. This is because NaOH is a strong base and will therefore produce a high concentration of OH- ions, resulting in a high pH. pH is a measure of the hydrogen ion concentration in a solution, with lower values indicating acidity and higher values indicating alkalinity or basicity.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2005>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following ions requires the largest quantity of electricity for discharge at an electrode?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.0 moles of Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0 moles of Na<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.5 moles of Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 moles of Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The quantity of electricity required for discharge at an electrode is directly proportional to the charge on the ion. Therefore, Al<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span> which has a charge of +3 will require the highest quantity of electricity for discharge. This is based on Faraday's first law of electrolysis which states that the amount of substance deposited or liberated at an electrode during electrolysis is directly proportional to the quantity of electricity passed.</div>", "topic": "ELECTROLYSIS : FACTORS AFFECTING DISCHARGE OF IONS AT THE ELECTRODES"}, {"id": "objective>Chemistry>2005>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Phenolphthalein in acidic solution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">red </div>", "<div style=\"font-family:Cambria;font-size:17px;\">orange </div>", "<div style=\"font-family:Cambria;font-size:17px;\">colourless </div>", "<div style=\"font-family:Cambria;font-size:17px;\">yellow</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Phenolphthalein is a chemical compound often used as a pH indicator in titrations. In an alkaline solution, phenolphthalein is pink, but it turns colourless in an acidic solution. phenolphthalein does not turn pink in a neutral solution. <br/> </div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>2005>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When iron is exposed to moisture and it rusts, the value of Δ G for the reaction is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">neutral    </div>", "<div style=\"font-family:Cambria;font-size:17px;\">zero </div>", "<div style=\"font-family:Cambria;font-size:17px;\">positive     </div>", "<div style=\"font-family:Cambria;font-size:17px;\">negative </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">ΔG represents the change in Gibbs free energy. For a spontaneous reaction, such as rusting, ΔG is negative. This is because the system is losing energy (in the form of work) to the surroundings.</div>", "topic": "ENERGY CHANGES : SPONTANEITY OF REACTIONS"}, {"id": "objective>Chemistry>2005>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which of the following reactions can the oxidation number of nitrogen be said to have increased?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>+ Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → NOCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(l)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">FeSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → Fe(NO)SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + Br<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(l)</span> → NOBr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(l)</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of nitrogen in NO is +2 and in NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is +4. Therefore, the oxidation number of nitrogen has increased in the reaction 2NO(g) + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2005>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O; ΔH = -571kJ  <br/> In the equation above, how much heat will be liberated if 12.0g of hydrogen is burnt in excess oxygen?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">–1142 kJ        </div>", "<div style=\"font-family:Cambria;font-size:17px;\">–571kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+1142 kJ        </div>", "<div style=\"font-family:Cambria;font-size:17px;\">–1713 kJ</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2 → 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O; ΔH = - 571KJ  <br/> 2 moles of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> releases -571KJ of heat    <br/> 6 moles i.e. (12g) will release (6× (-571))/2 =  - 1713KJ.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2005>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A concentrated solution containing H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>,Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>, OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> and Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">- </span>was electrolyzed using platinum electrodes. The ion that will be discharged at the cathode is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During electrolysis, reduction occurs at the cathode. Among the ions present, Cu<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> is the most easily reduced, so it will be discharged at the cathode.</div>", "topic": "ELECTROLYSIS : FACTORS AFFECTING DISCHARGE OF IONS AT THE ELECTRODES"}, {"id": "objective>Chemistry>2005>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When sulphur(IV)oxide is passed into a solution of sodium hydroxide for a long <br/> time, it eventually produces a solution of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NaHSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaHSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When sulphur(IV)oxide is passed into a solution of sodium hydroxide for a long time, it eventually produces a solution of sodium hydrogen sulphite (NaHSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>). This is because sulphur(IV)oxide reacts with sodium hydroxide to form sodium sulphite and water initially. However, with excess sulphur(IV)oxide, sodium hydrogen sulphite is formed.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2005>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the correct IUPAC name for NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Dioxonitrate(IV) ion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trioxonitrate(III) ion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Trioxonitrate(IV) ion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dioxonitrate(III) ion</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct IUPAC name for NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> is Dioxonitrate(III) ion. In IUPAC nomenclature, the oxidation state of the central atom (in this case nitrogen) is indicated in Roman numerals in parentheses. The prefix 'di-' indicates that there are two oxygen atoms, and 'nitrate' is the name for the NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> group.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2005>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What will happen if an aluminium spoon is used to stir a solution of iron(II)trioxonitrate(V)?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The spoon will be oxidized while the iron(II) ions will be reduced to the metal.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The spoon will increase in size</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The spoon will be reduced while the iron (II) ions will be oxidized.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The spoon will be reduced</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">If an aluminium spoon is used to stir a solution of iron(II)trioxonitrate(V), the spoon will be oxidized while the iron(II) ions will be reduced to the metal. This is because aluminium is more reactive than iron and will therefore displace the iron ions in the solution, resulting in the oxidation of aluminium and reduction of iron.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2005>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The IUPAC nomenclature for the hydrocarbon above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1,2-dimethylprop-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1,1-dimethylprop-2-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylbut-3-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-methylbut-1-ene</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">3-methylbut-1-ene.  <br/> The functional group is the double bond which is attached to the first carbon.  <br/> The longest continuous carbon chain is 4 , so the root name is but-1-ene, because the double bond is on the first carbon atom. <br/> There is a methyl substituent on the third carbon, so we name it as 3-methyl. <br/> All together we have 3-methylbut-1-ene.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2005>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The enzyme responsible for converting sucrose into two simple isomeric sugars is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">maltase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">amylase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">invertase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">lactase</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The enzyme responsible for converting sucrose into two simple isomeric sugars (glucose and fructose) is invertase. Invertase is an enzyme that catalyzes the hydrolysis (breakdown with the addition of water) of sucrose, a disaccharide, into the two monosaccharides glucose and fructose.</div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}, {"id": "objective>Chemistry>2005>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The decolourization of the purple colour of tetraoxomanganate (VII) ion is a test for</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkenes </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanes</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The decolourization of the purple colour of tetraoxomanganate (VII) ion is a test for alkenes. This is because alkenes are unsaturated hydrocarbons that contain a carbon-carbon double bond, which can undergo addition reactions. In this case, the alkene reacts with the purple tetraoxomanganate(VII) ion, reducing it to a colourless solution and confirming the presence of the alkene.</div>", "topic": "OXIDATION AND REDUCTION : TEST FOR OXIDIZING AND REDUCING AGENTS"}, {"id": "objective>Chemistry>2005>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are structural isomers?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Propanoic acid and propan-1,2-diol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Propanal and propanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethanoic acid and propanoic acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ethan-1,2-diol and ethanoic acid</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Propanal and Propanone; Alkanals and Alkanones exhibit structural isomerism.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2005>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the purification of impure samples of ethyl ethanoate synthesized by esterificaton, concentrated sodium trioxocarbonate(IV) solution is used to remove</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water </div>", "<div style=\"font-family:Cambria;font-size:17px;\">basic impurities</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acidic impurities </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethoxyethane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the purification of ethyl ethanoate, concentrated sodium trioxocarbonate(IV) solution is used to remove acidic impurities. This is because sodium trioxocarbonate(IV) is a base and it reacts with the acidic impurities to form a salt and water, thereby removing the acidic impurities.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2005>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many hydrogen atoms does a single ring cycloalkane have less than the corresponding open-chain alkane?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Two </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Three </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Four </div>", "<div style=\"font-family:Cambria;font-size:17px;\">One</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A single ring cycloalkane has two less hydrogen atoms than the corresponding open-chain alkane. This is because in forming the ring, two hydrogen atoms are lost to form the bond that closes the ring.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2005>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Equal moles of ethyne and hydrogen iodide react to give</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> – CHI</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> – Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = CHI</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equation of the reaction <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + HI → CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = CHI <br/> (ethyne) &nbsp &nbsp &nbsp (Hydrogen Iodide)</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2005>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A substance that is used as a ripening agent for fruits is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethene </div>", "<div style=\"font-family:Cambria;font-size:17px;\">propene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methane </div>", "<div style=\"font-family:Cambria;font-size:17px;\">butane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ethene is used as a ripening agent for fruits. It is a plant hormone that promotes ripening. When fruits are exposed to ethene, it speeds up the ripening process.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2005>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When water boilers are used for a long period of time, the solid substances left behind as scale are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magnesium trioxosilicate (IV) and rust</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnesium trioxosilicate(IV) and calcium tetraoxosulphate(VI)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay and magnesium trioxosilicate(IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay and rust</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When water boilers are used for a long period of time, the solid substances left behind as scale are magnesium trioxosilicate(IV) and calcium tetraoxosulphate(VI). These are formed due to the hardness of water which is caused by the presence of dissolved bicarbonates, chlorides, and sulphates of calcium and magnesium.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2005>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a mixture of noble gases was obtained from air after the removal of other constituents. What was the original volume of air?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2500 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1500 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">125 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">80 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The volume of noble gases in the atmosphere is approximately 1% of the total volume. Therefore, if 25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a mixture of noble gases was obtained from air, the original volume of air would be 25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> / 0.01 = 2500 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2005>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility curve shows the variation of solute concentration with</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">volume </div>", "<div style=\"font-family:Cambria;font-size:17px;\">temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">vapour density </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pressure</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility curve shows the variation of solute concentration with temperature. As the temperature increases, the solubility of most solids in water increases.</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2005>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The air around smelting industries is likely to contain</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>S, CO and N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The air around smelting industries is likely to contain SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. This is because during the smelting process, sulfur in the ore is oxidized to SO2, and carbon in the ore is oxidized to CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is a major component of the atmosphere and is likely to be present in the air around smelting industries.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2005>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Kerosine is commonly used to remove the red colour stain of palm oil from clothes because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">helps to spread the oil over a larger surface area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reacts with the oil to form an odourless compound</div>", "<div style=\"font-family:Cambria;font-size:17px;\">makes the oil to evaporate easily by dissolving it</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helps to dilute the oil and reduce its colour</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Kerosene is a non-polar solvent that can dissolve non-polar substances such as oils. When kerosene is applied to the oil stain, it dissolves the oil, making it easier to remove from the fabric. This is due to the principle of 'like dissolves like', where polar substances dissolve polar substances and non-polar substances dissolve non-polar substances.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2005>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that is the most dangerous pollutant to humans is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sulphur(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon(IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen(II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen sulphide</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that is the most dangerous pollutant to humans is hydrogen sulphide. Because it is poisonous.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2005>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Natural water collected from rivers and ponds contains oxygen, carbon(IV) oxide and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrogen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur(IV)oxide</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Natural water collected from rivers and ponds contains oxygen, carbon(IV) oxide and nitrogen. Nitrogen is a part of the natural composition of water bodies, as it is a major component of the atmosphere and can dissolve into water.</div>", "topic": "WATER : COMPOSITION BY VOLUME"}, {"id": "objective>Chemistry>2005>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many moles of limestone will be required to produce 5.6g of CaO?  <br/> [Ca = 4, C = 12, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.20mol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.10mol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.12mol </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.56mol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>→ CaO + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/> CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 40 + 12 + 16 * 3=100 <br/> CaO=40 + 16 =56 <br/> 100g of CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> → 56g of CaO  <br/> (5.6 x 100)/56=10g  0f CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> <br/> moles=mass/Molar mass=10/100=0.10mol <br/> </div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>2005>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the hydrocarbon compound CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">square planar </div>", "<div style=\"font-family:Cambria;font-size:17px;\">planar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">linear </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetrahedral</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the hydrocarbon compound CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> (Methane) is tetrahedral. This is due to the sp<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> hybridization of the carbon atom in methane which results in four equivalent bonds in a perfect tetrahedral geometry.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>2005>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these properties gives a solid its definite shape?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Strong intermolecular attraction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High melting point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">High boiling point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Weak intermolecular attraction</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The definite shape of a solid is due to strong intermolecular attraction. In solids, the particles (ions, atoms or molecules) are closely packed together. The forces between these particles are strong enough to keep the particles close together, giving solids a definite shape.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2005>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sugar is separated from its impurities by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">precipitation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">crystallization</div>", "<div style=\"font-family:Cambria;font-size:17px;\">distillation </div>", "<div style=\"font-family:Cambria;font-size:17px;\">evaporation</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sugar is separated from its impurities by crystallization. Crystallization is a separation technique that is used to separate a solid that has dissolved in a liquid and made a solution. The solution is warmed in an open container, allowing the solvent to evaporate, leaving a saturated solution. When the saturated solution cools, the solid comes out of the solution and forms crystals.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2005>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The component of an atom that contributes least to its mass is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">proton </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nucleus</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutron </div>", "<div style=\"font-family:Cambria;font-size:17px;\">electron</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The component of an atom that contributes least to its mass is the electron. An atom consists of protons, neutrons, and electrons. Protons and neutrons are located in the nucleus of the atom and have roughly the same mass, which is much larger than that of the electron. Electrons are located in the electron cloud outside the nucleus and have a much smaller mass compared to protons and neutrons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2005>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An element will readily form an electrovalent compound if its electron configuration is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2,8,1 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 8, 4 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 8, 8 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2, 8,5</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An element will readily form an electrovalent compound if its electron configuration is 2,8,1. Electrovalent (or ionic) compounds are formed when atoms lose or gain electrons to achieve a full outer shell of electrons. An element with an electron configuration of 2,8,1 has one electron in its outer shell, and it can readily form an electrovalent compound by losing this electron to achieve a full outer shell of 8 electrons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2005>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A heterogenous mixture can be defined as any mixture</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">of a solute and a solvent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">whose composition is uniform</div>", "<div style=\"font-family:Cambria;font-size:17px;\">whose composition is not uniform</div>", "<div style=\"font-family:Cambria;font-size:17px;\">formed by solids and liquids</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A heterogeneous mixture can be defined as any mixture whose composition is not uniform. In a heterogeneous mixture, the different components can be visually distinguished, and the composition varies from one region to another.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : ELEMENTS COMPOUNDS AND MIXTURES"}, {"id": "objective>Chemistry>2005>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pressure of 100 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen at 350°C is 750mmHg. What will be the volume of the gas if the pressure is reduced to 100mmHg without changing the temperature?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">650 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">850 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">580cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">750 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>= P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=100cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=350+273=623K, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=750mmHg, P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=100mmHg, T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=350+273=623K <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=? <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>/T<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=750 x 100 x 623/100 x 623 <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>=46725000/62300 <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 750cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>. <br/> </div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2005>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I.Treatment of cancer  <br/> II.Detection of leakages in water mains  <br/>  III.Detection of the ages of ancient tools  <br/> IV.Preparation of drugs  <br/>  <br/> Which combination of the above refers to the uses of radioactive isotopes?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II and III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II and III </div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and IV</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Radioactive isotopes have several uses including: I. Treatment of cancer - Radioactive isotopes are used in radiation therapy to treat cancer. II. Detection of leakages in water mains - Radioactive isotopes can be used to trace the path of water to detect leaks. III. Detection of the ages of ancient tools - This is done through a process called radiocarbon dating. IV. Preparation of drugs - Radioactive isotopes are used in the preparation of radiopharmaceuticals.</div>", "topic": "NUCLEAR CHEMISTRY : NUCLEAR REACTIONS"}, {"id": "objective>Chemistry>2005>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the valence shell electron configuration of the element with atomic number 17?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Chlorine, <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">17</span>Cl => 2, 8, 7 <br/> Chlorine has 7 valence electrons <br/> <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">17</span>Cl => 3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span> <br/> Valence shell electrons.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2005>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The density of a certain gas is 1.98gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>at s.t.p. What is the molecular mass of the gas?  <br/> [Molar volume of gas at s.t.p = 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">44.0g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">54.0g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">26.0g </div>", "<div style=\"font-family:Cambria;font-size:17px;\">31.0g</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The density of the gas at s.t.p = 1.98g/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/> 1.98g of the gas occupies 1dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at s.t.p <br/> xg of the gas willl occupies 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at s.t.p <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">x<hr size=\"1\" />1.98</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">22.4<hr size=\"1\" />1</td></tr></table></div> <br/> x = 22.4 x 1.98 <br/> x = 44.0g <br/> 44.0g is the mass of one molecule (or mole) of the gas.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>2005>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When pure aluminium metal is heated to red hot in the presence of nitrogen gas, the compound formed is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>N </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">AlN </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Al<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2Al + N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2AlN <br/> Aluminium reacts with nitrogen to produce aluminium nitride. The reaction takes place at a temperature between 800<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C - 1200<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2005>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A dense white fume (ammonium chloride) is formed when ammonia gas reacts with.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ammonia gas reacts with Hydrogen chloride gas (HCl) to form a dense white fume of Ammonium chloride. The reaction is as follows: NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> + HCl(g) -> →NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl(s). The other options do not react with ammonia to form ammonium chloride.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2005>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ⇌ 2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> ΔH = -90kJ  <br/>  In the equation above, the yield of ammonia can be decreased by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing the pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">removing ammonia as it is formed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increasing the temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">adding a catalyst</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Given the equilibrium reaction <br/> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + 3H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> ≒2NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> ∆H = -90KJ <br/> Two things can actually decrease the yield of ammonia. <br/> i. A decrease in the pressure of the system since we have higher number of moles of gaseous reactant <br/> ii. An increase in the temperature since the reaction is an exothermic reaction.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2005>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The gas that can be dried using concentrated tetraoxosulphate(VI) acid is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen bromide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen sulphide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ammonia</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur(IV)Oxide can be dried using concentrated tetraoxosulphate(VI)acid. Note that drying agents that are acidic are not used to dry bases or any alkaline substance in order to prevent their reactions.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2005>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>→ NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> + HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>  <br/>  The reaction above can only attain equilibrium if</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">a gaseous reactant is added</div>", "<div style=\"font-family:Cambria;font-size:17px;\">one of the products is removed</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is in a closed system</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it is in an open system</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A reaction can only attain equilibrium in a closed system. In an open system, the products would escape, preventing equilibrium. Adding a gaseous reactant or removing one of the products would shift the equilibrium, not establish it.</div>", "topic": "CHEMICAL EQUILIBRA : REVERSIBLE REACTIONS"}, {"id": "objective>Chemistry>2005>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most suitable metal that can be used as a lightning conductor is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">silver </div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper </div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron </div>", "<div style=\"font-family:Cambria;font-size:17px;\">aluminium</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper is the most suitable metal for a lightning conductor. It has excellent electrical conductivity and is less expensive than silver, another good conductor. Iron is not a good choice because it rusts, and aluminium, while a good conductor, is not as durable as copper.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2005>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the diagram above, which of the curves illustrates Arrhenius' law?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Y </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z </div>", "<div style=\"font-family:Cambria;font-size:17px;\">R </div>", "<div style=\"font-family:Cambria;font-size:17px;\">X</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Arrhenius equation, <br/> k = Ae<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-Ea/RT</span> <br/> lnK = lnAe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-Ea/RT</span> <br/> lnK = lnA + lne<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-Ea/RT</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">lnK</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">lnA</td><td style=\"text-align:center;\">-</td><td style=\"text-align:center;\">Ea<hr size=\"1\" />Rt</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">lnK</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-Ea<hr size=\"1\" />RT</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">lnA</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">lnK</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">-Ea<hr size=\"1\" />R</td><td style=\"text-align:center;\">)(</td><td style=\"text-align:center;\">1<hr size=\"1\" />T</td><td style=\"text-align:center;\">)</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">lnA</td></tr></table></div> <br/> y = m x + c <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m(slope)</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-Ea<hr size=\"1\" />R</td><td style=\"text-align:center;\">(negative)</td></tr></table></div> Hence, the straight line falls from top left to bottom right.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2005>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The most abundant element on the earth's crust is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitrogen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fluorine</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The most abundant element in the Earth's crust is oxygen, making up 46.6% of Earth's mass. Silicon is the second most abundant element (27.7%), followed by aluminum (8.1%), iron (5.0%), calcium (3.6%), sodium (2.8%), potassium (2.6%).</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2005>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Metalloids are also referred to as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">semi-metals </div>", "<div style=\"font-family:Cambria;font-size:17px;\">metals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">colloids </div>", "<div style=\"font-family:Cambria;font-size:17px;\">non-metals</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Metalloids are also referred to as semi-metals. They have properties of both metals and non-metals.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2005>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ores that can be concentrated by flotation are</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">nitride ores </div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphide ores</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxide ores </div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloride ores</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Flotation is a process used to separate minerals that are attracted to water (hydrophilic) from those that repel water (hydrophobic). Sulphide ores are hydrophobic and can be concentrated by flotation. Nitride, oxide, and chloride ores are not typically concentrated by this method.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2005>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The property used in the industrial preparation of nitrogen and oxygen from air is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">rate of diffusion </div>", "<div style=\"font-family:Cambria;font-size:17px;\">density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">boiling point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">solubility</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The industrial preparation of nitrogen and oxygen from air is based on the property of boiling point. This process is known as fractional distillation of air. In this process, air is liquefied and then fractionally distilled to separate its components based on their different boiling points.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2005>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a flame test for calcium, the flame appears</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">green when viewed through a blue glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue when viewed through a blue glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">orange-red when viewed through a blue glass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brick-red when viewed through a blue glass</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calcium flame appears green when viewed through a blue flame glass.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2005>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following alloys contains iron?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Duralumin and steel</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Brass and bronze</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steel and permalloy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Soft solder and duralumin</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Steel and permalloy are alloys that contain iron. Steel is an alloy of iron and carbon, and permalloy is an alloy of iron and nickel. Duralumin is an alloy of aluminum, copper, and other elements, and does not contain iron. Brass is an alloy of copper and zinc, and bronze is an alloy of copper and tin, neither of which contain iron.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALLOY"}, {"id": "objective>Chemistry>2005>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To obtain pure carbon(II) oxide from its mixture with carbon(IV) oxide, the mixture should be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">passed over heated copper(II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bubbled through water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bubbled through concentrated tetraoxosulphate(VI) acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bubbled through sodium hydroxide.</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The sodium hydroxide reacts with the carbon (IV)oxide component leaving behind the carbon(II) oxide.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}];
